import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const c=JSON.parse('{"title":"12. シフト管理","description":"","frontmatter":{},"headers":[],"relativePath":"internal/features/12-shift.md","filePath":"internal/features/12-shift.md"}'),l={name:"internal/features/12-shift.md"};function i(h,t,o,n,b,s){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_12-シフト管理" tabindex="-1">12. シフト管理 <a class="header-anchor" href="#_12-シフト管理" aria-label="Permalink to &quot;12. シフト管理&quot;">​</a></h1><p>シフト管理機能は<strong>proプラン以上</strong>で利用できます。管理ダッシュボードの「シフト管理」タブから利用します。</p><p>マネージャーはシフトの作成・割当・集計の全機能を使用でき、スタッフは自分のシフト確認・希望提出・勤怠打刻のみ操作できます。</p><h2 id="_12-1-サブタブ一覧" tabindex="-1">12.1 サブタブ一覧 <a class="header-anchor" href="#_12-1-サブタブ一覧" aria-label="Permalink to &quot;12.1 サブタブ一覧&quot;">​</a></h2><table tabindex="0"><thead><tr><th>サブタブ</th><th>対象ロール</th><th>説明</th></tr></thead><tbody><tr><td>週間カレンダー</td><td>マネージャー</td><td>シフトの割当・編集メイン画面</td></tr><tr><td>マイシフト</td><td>スタッフ</td><td>自分の確定シフト閲覧</td></tr><tr><td>希望提出</td><td>スタッフ</td><td>希望シフトの提出</td></tr><tr><td>勤怠一覧</td><td>マネージャー</td><td>全スタッフの出退勤記録</td></tr><tr><td>テンプレート</td><td>マネージャー</td><td>シフトパターンの定義</td></tr><tr><td>シフト設定</td><td>マネージャー</td><td>各種設定</td></tr><tr><td>集計サマリー</td><td>マネージャー</td><td>労働時間・人件費・労基法警告の集計</td></tr><tr><td>ヘルプ</td><td>マネージャー</td><td>他店舗へのスタッフ派遣要請（enterpriseプラン）</td></tr></tbody></table><hr><h2 id="_12-2-シフトテンプレート" tabindex="-1">12.2 シフトテンプレート <a class="header-anchor" href="#_12-2-シフトテンプレート" aria-label="Permalink to &quot;12.2 シフトテンプレート&quot;">​</a></h2><p>シフトテンプレートは、繰り返し使用するシフトパターン（早番・遅番・通しなど）を定義する機能です。</p><h3 id="テンプレートの作成" tabindex="-1">テンプレートの作成 <a class="header-anchor" href="#テンプレートの作成" aria-label="Permalink to &quot;テンプレートの作成&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>説明</th></tr></thead><tbody><tr><td>曜日</td><td>セレクト</td><td>月〜日のいずれか</td></tr><tr><td>開始時刻</td><td>時刻入力</td><td>シフト開始時間</td></tr><tr><td>終了時刻</td><td>時刻入力</td><td>シフト終了時間</td></tr><tr><td>役割ヒント</td><td>テキスト</td><td>役割名（例：ホール、キッチン）</td></tr><tr><td>必要人数</td><td>数値</td><td>その時間帯に必要なスタッフ数</td></tr></tbody></table><h3 id="テンプレートの一括適用" tabindex="-1">テンプレートの一括適用 <a class="header-anchor" href="#テンプレートの一括適用" aria-label="Permalink to &quot;テンプレートの一括適用&quot;">​</a></h3><p>作成したテンプレートを指定した期間に一括適用できます。</p><ol><li>テンプレート一覧から適用するテンプレートを選択します</li><li>適用期間（開始日〜終了日）を指定します</li><li>「適用」ボタンをクリックすると、期間内の該当曜日にシフト枠が自動生成されます</li></ol><hr><h2 id="_12-3-週間カレンダー" tabindex="-1">12.3 週間カレンダー <a class="header-anchor" href="#_12-3-週間カレンダー" aria-label="Permalink to &quot;12.3 週間カレンダー&quot;">​</a></h2><p>シフトの割当・編集を行うメイン画面です。</p><h3 id="カレンダーの表示" tabindex="-1">カレンダーの表示 <a class="header-anchor" href="#カレンダーの表示" aria-label="Permalink to &quot;カレンダーの表示&quot;">​</a></h3><ul><li>横軸：曜日（月〜日の1週間）</li><li>縦軸：スタッフ名</li><li>各セルにシフト情報（開始〜終了時刻、休憩、役割）が表示されます</li><li>セルの人件費（時給 × 時間）が計算されて表示されます</li></ul><h3 id="シフトの割当" tabindex="-1">シフトの割当 <a class="header-anchor" href="#シフトの割当" aria-label="Permalink to &quot;シフトの割当&quot;">​</a></h3><ol><li>カレンダーのセルをクリックします</li><li>シフト入力フォームが表示されます</li><li>以下を入力します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>開始時刻</td><td>シフト開始時間</td></tr><tr><td>終了時刻</td><td>シフト終了時間</td></tr><tr><td>休憩時間（分）</td><td>休憩の長さ</td></tr><tr><td>役割</td><td>ホール、キッチンなど</td></tr><tr><td>ステータス</td><td>draft（下書き）/ published（公開）</td></tr></tbody></table><ol start="4"><li>「保存」ボタンをクリックします</li></ol><h3 id="aiシフト提案" tabindex="-1">AIシフト提案 <a class="header-anchor" href="#aiシフト提案" aria-label="Permalink to &quot;AIシフト提案&quot;">​</a></h3><p>カレンダー画面に紫色の「AI提案」ボタンがあります。クリックすると、AIが以下のデータを分析して最適なシフトを提案します。</p><ul><li>テンプレート定義</li><li>スタッフの希望提出状況</li><li>過去4週間のスタッフ配置実績</li><li>各スタッフの時給</li><li>直近の出勤状況（出勤日数、遅刻回数）</li><li>連続勤務日数</li><li>曜日・時間帯別の平均売上</li></ul><hr><h2 id="_12-4-スタッフの希望提出" tabindex="-1">12.4 スタッフの希望提出 <a class="header-anchor" href="#_12-4-スタッフの希望提出" aria-label="Permalink to &quot;12.4 スタッフの希望提出&quot;">​</a></h2><p>スタッフは「希望提出」サブタブから、シフトの希望を提出します。</p><h3 id="提出方法" tabindex="-1">提出方法 <a class="header-anchor" href="#提出方法" aria-label="Permalink to &quot;提出方法&quot;">​</a></h3><ol><li>カレンダーで日付を選択します</li><li>各日付について以下を入力します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>可否</td><td>出勤可能 / 希望 / 出勤不可</td></tr><tr><td>希望開始時刻</td><td>—</td></tr><tr><td>希望終了時刻</td><td>—</td></tr><tr><td>メモ</td><td>特記事項</td></tr></tbody></table><ol start="3"><li>「提出」ボタンをクリックします</li><li>最大31日分を一括提出できます</li></ol><p><strong>更新方式：</strong> 同じ日に再提出すると上書きされます（UPSERT方式）。</p><hr><h2 id="_12-5-マイシフト" tabindex="-1">12.5 マイシフト <a class="header-anchor" href="#_12-5-マイシフト" aria-label="Permalink to &quot;12.5 マイシフト&quot;">​</a></h2><p>スタッフは「マイシフト」サブタブで、自分の確定したシフトを確認できます。</p><h3 id="表示内容" tabindex="-1">表示内容 <a class="header-anchor" href="#表示内容" aria-label="Permalink to &quot;表示内容&quot;">​</a></h3><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>日付</td><td>—</td></tr><tr><td>開始時刻〜終了時刻</td><td>—</td></tr><tr><td>休憩時間</td><td>—</td></tr><tr><td>役割</td><td>—</td></tr><tr><td>ステータス</td><td>draft / published</td></tr><tr><td>ヘルプ元店舗名</td><td>他店舗からのヘルプ要請で割り当てられた場合に表示</td></tr></tbody></table><hr><h2 id="_12-6-勤怠打刻" tabindex="-1">12.6 勤怠打刻 <a class="header-anchor" href="#_12-6-勤怠打刻" aria-label="Permalink to &quot;12.6 勤怠打刻&quot;">​</a></h2><h3 id="出勤・退勤ボタン" tabindex="-1">出勤・退勤ボタン <a class="header-anchor" href="#出勤・退勤ボタン" aria-label="Permalink to &quot;出勤・退勤ボタン&quot;">​</a></h3><p>スタッフロールでログインすると、管理ダッシュボードのヘッダー付近に<strong>出勤ボタン</strong>と<strong>退勤ボタン</strong>が常時表示されます。全てのタブで表示されるため、いつでも打刻できます。</p><h3 id="出勤打刻の流れ" tabindex="-1">出勤打刻の流れ <a class="header-anchor" href="#出勤打刻の流れ" aria-label="Permalink to &quot;出勤打刻の流れ&quot;">​</a></h3><ol><li>「出勤」ボタンをタップします</li><li>GPS検証が行われます（GPS必須が有効な場合） <ul><li>店舗の座標と現在地のGPS距離をハーバーサイン公式で計算</li><li>設定された許容半径内でなければエラー</li></ul></li><li>二重打刻のチェック（既に出勤中の場合はエラー）</li><li>予定シフトとの照合</li><li>早出警告（設定された時間より前に出勤した場合）</li><li>出勤が記録されます</li></ol><h3 id="退勤打刻の流れ" tabindex="-1">退勤打刻の流れ <a class="header-anchor" href="#退勤打刻の流れ" aria-label="Permalink to &quot;退勤打刻の流れ&quot;">​</a></h3><ol><li>「退勤」ボタンをタップします</li><li>退勤時刻が記録されます</li><li>休憩時間が自動計算されます <ul><li>勤務時間が6時間以上：デフォルト60分の休憩</li><li>勤務時間が6時間未満：休憩なし（0分）</li></ul></li></ol><h3 id="勤怠データの記録内容" tabindex="-1">勤怠データの記録内容 <a class="header-anchor" href="#勤怠データの記録内容" aria-label="Permalink to &quot;勤怠データの記録内容&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>打刻方法</td><td>manual（手動）、biometric、RFID等</td></tr><tr><td>ステータス</td><td>working（勤務中）→ completed（完了）</td></tr><tr><td>出勤時刻</td><td>—</td></tr><tr><td>退勤時刻</td><td>—</td></tr><tr><td>休憩時間</td><td>—</td></tr></tbody></table><hr><h2 id="_12-7-勤怠一覧" tabindex="-1">12.7 勤怠一覧 <a class="header-anchor" href="#_12-7-勤怠一覧" aria-label="Permalink to &quot;12.7 勤怠一覧&quot;">​</a></h2><p>マネージャーは「勤怠一覧」サブタブで、全スタッフの出退勤記録を確認できます。</p><hr><h2 id="_12-8-シフト設定" tabindex="-1">12.8 シフト設定 <a class="header-anchor" href="#_12-8-シフト設定" aria-label="Permalink to &quot;12.8 シフト設定&quot;">​</a></h2><p>「シフト設定」サブタブで以下の項目を設定します。</p><table tabindex="0"><thead><tr><th>設定項目</th><th>説明</th></tr></thead><tbody><tr><td>デフォルト時給</td><td>店舗全体のデフォルト時給（スタッフ個別の時給が未設定の場合に使用）</td></tr><tr><td>デフォルト休憩時間</td><td>—</td></tr><tr><td>残業閾値（分）</td><td>この時間を超えた分が残業として計算されます</td></tr><tr><td>早出許容時間（分）</td><td>シフト開始の何分前から出勤を許可するか</td></tr><tr><td>GPS必須</td><td>ONにすると、出退勤時にGPS位置情報の検証が必要になります</td></tr><tr><td>店舗緯度</td><td>GPS検証用の店舗の緯度</td></tr><tr><td>店舗経度</td><td>GPS検証用の店舗の経度</td></tr><tr><td>GPS許容半径（メートル）</td><td>店舗からこの距離以内でのみ打刻を許可</td></tr></tbody></table><hr><h2 id="_12-9-集計サマリー" tabindex="-1">12.9 集計サマリー <a class="header-anchor" href="#_12-9-集計サマリー" aria-label="Permalink to &quot;12.9 集計サマリー&quot;">​</a></h2><p>「集計サマリー」サブタブで、労働時間と人件費の集計を確認します。</p><h3 id="集計期間" tabindex="-1">集計期間 <a class="header-anchor" href="#集計期間" aria-label="Permalink to &quot;集計期間&quot;">​</a></h3><ul><li>週単位 / 月単位 で選択</li><li>日付範囲のカスタム指定も可能</li></ul><h3 id="スタッフ別集計" tabindex="-1">スタッフ別集計 <a class="header-anchor" href="#スタッフ別集計" aria-label="Permalink to &quot;スタッフ別集計&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>合計勤務時間</td><td>期間内の総勤務時間</td></tr><tr><td>出勤日数</td><td>—</td></tr><tr><td>残業時間</td><td>残業閾値を超えた時間の合計</td></tr><tr><td>時給</td><td>スタッフ個別の時給（未設定の場合は店舗デフォルト）</td></tr><tr><td>人件費</td><td>時給 × 勤務時間（深夜割増含む）</td></tr></tbody></table><h3 id="深夜割増計算" tabindex="-1">深夜割増計算 <a class="header-anchor" href="#深夜割増計算" aria-label="Permalink to &quot;深夜割増計算&quot;">​</a></h3><p>22:00〜05:00の勤務は深夜割増（25%増）が自動計算されます。</p><h3 id="労基法コンプライアンスチェック" tabindex="-1">労基法コンプライアンスチェック <a class="header-anchor" href="#労基法コンプライアンスチェック" aria-label="Permalink to &quot;労基法コンプライアンスチェック&quot;">​</a></h3><p>以下の警告が自動で検出・表示されます。</p><table tabindex="0"><thead><tr><th>警告</th><th>条件</th></tr></thead><tbody><tr><td>週40時間超過</td><td>1週間の勤務合計が40時間を超えた場合</td></tr><tr><td>休憩不足（8時間以上）</td><td>8時間以上の勤務で60分未満の休憩</td></tr><tr><td>休憩不足（6時間以上）</td><td>6時間以上の勤務で45分未満の休憩</td></tr><tr><td>連続勤務</td><td>連続で勤務日が続いている場合</td></tr></tbody></table><h3 id="日別詳細" tabindex="-1">日別詳細 <a class="header-anchor" href="#日別詳細" aria-label="Permalink to &quot;日別詳細&quot;">​</a></h3><p>各スタッフの日別詳細データも確認できます。</p><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>日付</td><td>—</td></tr><tr><td>実労働時間（分）</td><td>—</td></tr><tr><td>休憩時間（分）</td><td>—</td></tr></tbody></table><hr><h2 id="_12-10-ヘルプ要請-enterpriseプラン" tabindex="-1">12.10 ヘルプ要請（enterpriseプラン） <a class="header-anchor" href="#_12-10-ヘルプ要請-enterpriseプラン" aria-label="Permalink to &quot;12.10 ヘルプ要請（enterpriseプラン）&quot;">​</a></h2><p>enterpriseプランでは、同じテナント内の他店舗にスタッフの派遣を要請できます。</p><h3 id="ヘルプ要請の送信" tabindex="-1">ヘルプ要請の送信 <a class="header-anchor" href="#ヘルプ要請の送信" aria-label="Permalink to &quot;ヘルプ要請の送信&quot;">​</a></h3><ol><li>「ヘルプ」サブタブを開きます</li><li>「ヘルプ要請を送信」ボタンをクリックします</li><li>以下を入力します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>派遣先店舗</td><td>ヘルプを要請する店舗</td></tr><tr><td>日付</td><td>派遣が必要な日</td></tr><tr><td>開始時刻</td><td>—</td></tr><tr><td>終了時刻</td><td>—</td></tr><tr><td>必要人数</td><td>—</td></tr><tr><td>役割ヒント</td><td>必要な役割（ホール、キッチン等）</td></tr><tr><td>メモ</td><td>補足情報</td></tr></tbody></table><ol start="4"><li>「送信」ボタンをクリックします</li></ol><h3 id="ヘルプ要請のステータス" tabindex="-1">ヘルプ要請のステータス <a class="header-anchor" href="#ヘルプ要請のステータス" aria-label="Permalink to &quot;ヘルプ要請のステータス&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ステータス</th><th>意味</th></tr></thead><tbody><tr><td>pending</td><td>要請中（承認待ち）</td></tr><tr><td>approved</td><td>承認済み（スタッフ割当済み）</td></tr><tr><td>rejected</td><td>拒否</td></tr><tr><td>cancelled</td><td>キャンセル</td></tr></tbody></table><h3 id="ヘルプ要請の承認" tabindex="-1">ヘルプ要請の承認 <a class="header-anchor" href="#ヘルプ要請の承認" aria-label="Permalink to &quot;ヘルプ要請の承認&quot;">​</a></h3><p>派遣先店舗のマネージャーが要請を確認し、スタッフを割り当てます。</p><ol><li>「ヘルプ」サブタブの「受信」タブで要請を確認します</li><li>「承認」ボタンをクリックします</li><li>派遣するスタッフを選択します</li><li>回答メモを入力します（任意）</li><li>承認するとスタッフのシフトが自動作成されます</li></ol><h3 id="送信-受信タブ" tabindex="-1">送信/受信タブ <a class="header-anchor" href="#送信-受信タブ" aria-label="Permalink to &quot;送信/受信タブ&quot;">​</a></h3><ul><li><strong>送信タブ：</strong> 自店舗から送信したヘルプ要請の一覧</li><li><strong>受信タブ：</strong> 他店舗から受信したヘルプ要請の一覧</li></ul>',84)])])}const q=d(l,[["render",i]]);export{c as __pageData,q as default};
